// Lava Lamp -- dual noise blend, warm oranges/magentas, heavy feedback
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

noise(1.8, 0.12)
  .color(
    () => 1.1 + low() * 0.5,
    () => 0.4 + mid() * 0.3,
    () => 0.15 + high() * 0.25
  )
  .blend(
    noise(4.5, 0.08)
      .color(
        () => 0.9 + mid() * 0.4,
        () => 0.15 + low() * 0.2,
        () => 0.55 + high() * 0.35
      ),
    0.45
  )
  .modulate(osc(3, 0.04, 1.5), () => 0.06 + low() * 0.01)
  .blend(src(o0).rotate(() => 0.003 + Math.sin(time * 0.02) * 0.001), 0.86)
  .saturate(() => 1.3 + low() * 0.35)
  .colorama(() => 0.002 + amp() * 0.004)
  .hue(() => mid() * 0.01)
  .contrast(() => 1.03 + low() * 0.06)
  .brightness(0.03)
  .out(o0)
